# Route to reasoning model only for complex tasks
def needsReasoning(prompt):
    signals = ['debug', 'analyze', 'prove', 'derive', 'plan', 'why does', 'step by step']
    return any(signal in prompt.lower() for signal in signals)

# Use reasoning for complexity, fast model for simple tasks
