params = {
    'model': 'claude-opus-4-7' if useReasoning else 'claude-haiku-4-5',
    'max_tokens': 8000 if useReasoning else 1000,
    'thinking': {'type': 'enabled', 'budget_tokens': 6000} if useReasoning else None
}

import anthropic

client = anthropic.Anthropic()

def stream_with_thinking(prompt, budget_tokens=6000):
    """Stream a response with extended thinking, showing progress."""
    thinking_chars = 0
    in_thinking = False

    with client.messages.stream(
        model="claude-opus-4-7",
        max_tokens=10000,
        thinking={"type": "enabled", "budget_tokens": budget_tokens},
        messages=[{"role": "user", "content": prompt}]
    ) as stream:
        for event in stream:
            if event.type == "content_block_start":
                if event.content_block.type == "thinking":
                    in_thinking = True
                    print("[Reasoning...]", end="", flush=True)
                elif event.content_block.type == "text":
                    in_thinking = False
                    print("\n[Answer]", flush=True)

            elif event.type == "content_block_delta":
                if event.delta.type == "thinking_delta" and in_thinking:
                    # Show thinking progress as character count
                    thinking_chars += len(event.delta.thinking)
                    print(f"\r[Reasoning... {thinking_chars} chars]", end="", flush=True)
                elif event.delta.type == "text_delta" and not in_thinking:
                    print(event.delta.text, end="", flush=True)

    print()  # Final newline

stream_with_thinking("Analyze the time complexity of merge sort and explain the recursion tree.")
